29	class LinkMap;
30	
31	class LoadBlock : public Block {
32	public:
33	    inline uint64_t begin() { return begin(OPT_READ_ALL); }
34	    inline uint64_t begin(int opt) {
35	        if (UNLIKELY(mOverlay && (opt & OPT_READ_OVERLAY)))
36	            return mOverlay->data();
37	        if (UNLIKELY(mMmap && (opt & OPT_READ_MMAP)))
38	            return mMmap->data();
39	        if (LIKELY(oraddr() && (opt & OPT_READ_OR)))
40	            return oraddr();
41	        return 0x0;
42	    }
43	    inline uint64_t size() { return size(OPT_READ_ALL); }
44	    inline uint64_t size(int opt) {
45	        if (UNLIKELY(mOverlay && (opt & OPT_READ_OVERLAY)))
46	            return mOverlay->size();
47	        if (UNLIKELY(mMmap && (opt & OPT_READ_MMAP)))
48	            return mMmap->size();
49	        if (LIKELY(oraddr() && (opt & OPT_READ_OR)))
50	            return realSize();
51	        return 0x0;
52	    }
53	    inline bool isValid() {
54	        if ((isValidBlock() || mMmap || mOverlay))
55	            return true;
56	        return false;
57	    }
58	    inline bool virtualContains(uint64_t addr) {
59	        uint64_t clocaddr = addr & mVabitsMask;
60	        if ((clocaddr < vaddr())
61	                || (clocaddr >= (vaddr() + size())))
62	            return false;
63	        return true;
64	    }
65	    inline bool realContains(uint64_t raddr) {
66	        if (mOverlay) {
67	            return (raddr >= mOverlay->data() && raddr < (mOverlay->data() + size()));
68	        } else if (mMmap) {
69	            return (raddr >= mMmap->data() && raddr < (mMmap->data() + size()));
70	        } else if (oraddr()) {
71	            return (raddr >= oraddr() && raddr < (oraddr() + size()));
72	        }
73	        return false;
74	    }
75	
76	    inline std::string convertValids() {
77	        std::string valid;
78	        if (isValid()) {
79	            valid.append("[*]");
80	            if (realSize() && realSize() != memsz()) {
81	                valid.append("(MEMSZ ");
82	                valid.append(Utils::ToHex(memsz()));
83	                valid.append(")");
84	            }
85	            if (isMmapBlock()) {
86	                valid.append("(MMAP");
87	                if (GetMmapOffset()) {
88	                    valid.append(" ");
89	                    valid.append(Utils::ToHex(GetMmapOffset()));
90	                }
91	                valid.append(")");
92	            }
93	            if (isOverlayBlock()) {
94	                valid.append("(OVERLAY)");
95	                if (isFake())
96	                    valid.append("(FAKE)");
97	            }
98	        } else {
99	            valid.append("[EMPTY]");
100	            if (isTruncated())
101	                valid.append("(TRUNCATE)");
102	        }
103	        return valid;
104	    }
105	
106	    LoadBlock(uint32_t f, uint64_t off, uint64_t va, uint64_t pa,
107	            uint64_t filesz, uint64_t memsz, uint64_t align)
108	            : Block(f, off, va, pa, filesz, memsz, align) {
109	        mVabitsMask = 0x0;
110	        mPointMask = 0x0;
111	        mCRC32 = 0x0;
112	        mLinkMap = nullptr;
113	    }
114	
115	    void setMmapFile(const char* file, uint64_t offset);
116	    void setOverlay(uint64_t addr, void *buf, uint64_t size);
117	    bool newOverlay();
118	    void removeMmap();
119	    void removeOverlay();
120	    inline bool isMmapBlock() { return mMmap != nullptr; }
121	    inline std::string& name() {
122	        if (isMmapBlock())
123	            return mMmap->getName();
124	        return mFileName;
125	    }
126	    inline std::string& filename() { return mFileName; }
127	    inline uint64_t pageoffset() { return mPageOffset; }
128	    inline void setVabitsMask(uint64_t mask) { mVabitsMask = mask; }
129	    inline void setPointMask(uint64_t mask) { mPointMask = mask; }
130	    inline uint64_t VabitsMask() { return mVabitsMask; }
131	    inline uint64_t PointMask() { return mPointMask; }
132	    inline uint64_t GetMmapOffset() { return mMmap->offset(); }
133	    inline void setMmapMemoryMap(std::unique_ptr<MemoryMap>& map) { mMmap = std::move(map); }
134	    inline std::unordered_set<SymbolEntry, SymbolEntry::Hash>& GetSymbols() { return mSymbols; }
135	    bool CheckCanMmap(uint64_t header);
136	    uint32_t GetCRC32(int opt);
137	    void bind(LinkMap* map) { mLinkMap = map; }
138	    void setFile(std::string& name, uint64_t off) {
139	        mFileName = name;
140	        mPageOffset = off;
141	    }
142	    LinkMap* handle() { return mLinkMap; }
143	
144	    ~LoadBlock() {
145	        mSymbols.clear();
146	        mMmap.reset();
147	    }
148	private:
149	    uint64_t mVabitsMask;
150	    uint64_t mPointMask;
151	    uint32_t mCRC32;
152	    std::string mFileName;
153	    uint64_t mPageOffset;
154	    LinkMap* mLinkMap;
155	    std::unique_ptr<MemoryMap> mMmap;
156	    std::unordered_set<SymbolEntry, SymbolEntry::Hash> mSymbols;
157	};
158	
