25	class SymbolEntry {
26	public:
27	    SymbolEntry(uint64_t off, uint64_t ty, uint64_t cs, const char* name) {
28	        offset = off;
29	        type = ty;
30	        size = cs;
31	        if (name) symbol = name;
32	    }
33	
34	    uint64_t offset;
35	    uint64_t type;
36	    uint64_t size;
37	    std::string symbol;
38	
39	    bool operator==(const SymbolEntry& entry) const {
40	        return offset == entry.offset
41	                && type == entry.type
42	                && size == entry.size;
43	    }
44	
45	    struct Hash {
46	        std::size_t operator()(const SymbolEntry& entry) const {
47	            std::hash<uint64_t> offset_hasher;
48	            std::hash<uint64_t> type_hasher;
49	            std::hash<uint64_t> size_hasher;
50	            return offset_hasher(entry.offset) ^ type_hasher(entry.type) ^ size_hasher(entry.size);
51	        }
52	    };
53	
54	    inline static const SymbolEntry Invalid() { return SymbolEntry(0, 0, 0, 0); }
55	    inline bool IsValid() { return offset != 0x0 && size != 0x0; }
56	};
