38	#define QUICK_CACHE(NAME) get_##NAME##_cache()
39	#define CACHE(NAME) NAME##_cache
40	
41	#define DEFINE_QUICK_CACHE(T, NAME) \
42	T CACHE(NAME) = 0x0; \
43	inline T& QUICK_CACHE(NAME) { \
44	    do { \
45	        if (!CACHE(NAME).Ptr()) {\
46	            CACHE(NAME) = NAME(); \
47	            CACHE(NAME).copyRef(this); \
48	            CACHE(NAME).Prepare(false); \
49	        } \
50	        return CACHE(NAME);\
51	    } while (0); \
52	} \
53	
54	#define DEFINE_QUICK_CACHE_COPY(T, NAME, REF) \
55	T CACHE(NAME) = 0x0; \
56	inline T& QUICK_CACHE(NAME) { \
57	    do { \
58	        if (!CACHE(NAME).Ptr()) {\
59	            CACHE(NAME) = NAME(); \
60	            CACHE(NAME).copyRef(QUICK_CACHE(REF)); \
61	            CACHE(NAME).Prepare(false); \
62	        } \
63	        return CACHE(NAME);\
64	    } while (0); \
65	} \
