34	bool Core::load() {
35	    pointer_mask = GENMASK_UL(bits() - 1, 0);
36	    vabits_mask = GENMASK_UL((VA_BITS ? VA_BITS : DEF_VA_BITS) - 1, 0);
37	
38	    auto callback = [this](OptionArgs& args) -> void * {
39	        switch(args.type) {
40	            case NT_PRSTATUS: {
41	                Elf64_prstatus* prs = reinterpret_cast<Elf64_prstatus *>(args.pos);
42	                ThreadInfo* thread = new ThreadInfo(prs->pr_pid, args.pos);
43	                memcpy(&thread->reg, &prs->pr_reg, sizeof(Register));
44	                return thread;
45	            } break;
46	            case NT_FPREGSET: {
47	                if (args.context) {
48	                    Elf64_fpregset* fpr = reinterpret_cast<Elf64_fpregset *>(args.pos);
49	                    ThreadInfo* thread = reinterpret_cast<ThreadInfo*>(args.context);
50	                    memcpy(&thread->fpr, fpr, sizeof(FpRegister));
51	                }
52	            } break;
53	            case NT_ARM_TLS: {
54	                if (args.context) {
55	                    Elf64_tls* tls = reinterpret_cast<Elf64_tls *>(args.pos);
56	                    ThreadInfo* thread = reinterpret_cast<ThreadInfo*>(args.context);
57	                    memcpy(&thread->tls, tls, sizeof(Tls));
58	                }
59	            } break;
60	            case NT_ARM_PAC_MASK: {
61	                user_pac_mask* uregs = reinterpret_cast<user_pac_mask *>(args.pos);
62	                data_mask = uregs->data_mask;
63	                insn_mask = uregs->insn_mask;
64	                // pointer_mask = (1ULL << (63 - __builtin_clzll(data_mask))) - 1;
65	                vabits_mask = GENMASK_UL(__builtin_ctzll(data_mask) - 1, 0);
66	            } break;
67	            case NT_ARM_TAGGED_ADDR_CTRL: {
68	                tagged_addr_ctrl = *reinterpret_cast<uint64_t *>(args.pos);
69	            } break;
70	            case NT_ARM_PAC_ENABLED_KEYS: {
71	                pac_enabled_keys = *reinterpret_cast<uint64_t *>(args.pos);
72	            } break;
73	        }
74	        return nullptr;
75	    };
76	    return load64(this, callback);
77	}
